import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"日坛公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/ritan-park.md","filePath":"parks/ritan-park.md","lastUpdated":null}'),n={name:"parks/ritan-park.md"};function i(d,t,o,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="日坛公园" tabindex="-1">日坛公园 <a class="header-anchor" href="#日坛公园" aria-label="Permalink to &quot;日坛公园&quot;">​</a></h1><blockquote><p>&quot;明清祭日之所，使馆区的宁静绿洲。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>日坛公园位于北京市朝阳区，是明清两代皇帝祭祀太阳神的地方。日坛始建于明嘉靖九年（1530年），与天坛、地坛、月坛、先农坛并列为明清五坛之一。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线永安里站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区日坛北路6号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>明嘉靖九年（1530年），明世宗朱厚熜决定实行天地分祀，在北京东郊建日坛，专祀太阳神。</p><h3 id="清代修缮" tabindex="-1">清代修缮 <a class="header-anchor" href="#清代修缮" aria-label="Permalink to &quot;清代修缮&quot;">​</a></h3><p>清代，日坛多次修缮，规模不断扩大。</p><h3 id="现代公园" tabindex="-1">现代公园 <a class="header-anchor" href="#现代公园" aria-label="Permalink to &quot;现代公园&quot;">​</a></h3><p>1950年代，日坛辟为公园，对外开放。现为日坛公园。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="日坛" tabindex="-1">日坛 <a class="header-anchor" href="#日坛" aria-label="Permalink to &quot;日坛&quot;">​</a></h3><p>日坛是公园的核心建筑，是明清皇帝祭祀太阳神的地方。</p><h4 id="布局" tabindex="-1">布局 <a class="header-anchor" href="#布局" aria-label="Permalink to &quot;布局&quot;">​</a></h4><ul><li><strong>坛台</strong>：方形，一层</li><li><strong>坛墙</strong>：方形，四面</li><li><strong>棂星门</strong>：坛南的正门</li></ul><h3 id="祭器库" tabindex="-1">祭器库 <a class="header-anchor" href="#祭器库" aria-label="Permalink to &quot;祭器库&quot;">​</a></h3><p>祭器库是存放祭祀器具的地方。</p><h3 id="神厨" tabindex="-1">神厨 <a class="header-anchor" href="#神厨" aria-label="Permalink to &quot;神厨&quot;">​</a></h3><p>神厨是制作祭祀食品的地方。</p><h3 id="具服殿" tabindex="-1">具服殿 <a class="header-anchor" href="#具服殿" aria-label="Permalink to &quot;具服殿&quot;">​</a></h3><p>具服殿是皇帝更衣的地方。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>日坛游览（约1小时）</strong>：</p><p>南门 → 日坛 → 祭器库 → 神厨 → 具服殿 → 北门</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线永安里站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、4路、43路等日坛路站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从建国门步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>免费入园</strong>：公园免费开放</li><li><strong>人少清静</strong>：游客较少，比较清静</li><li><strong>结合游览</strong>：可与使馆区、CBD一起游览</li><li><strong>跑步好地方</strong>：适合跑步、散步</li><li><strong>使馆区</strong>：周围是使馆区</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">使馆区</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">各国使馆</td></tr><tr><td style="text-align:left;">CBD</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">商务中心</td></tr><tr><td style="text-align:left;">秀水街</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">购物街</td></tr><tr><td style="text-align:left;">日坛国际贸易中心</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">购物中心</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>日坛是明清五坛之一，是中国古代祭祀文化的重要遗存。</p><p>日坛与天坛、地坛、月坛、先农坛相对应，体现了中国古代&quot;天南地北，日东月西&quot;的宇宙观念。</p><hr><p><strong>📍 地址</strong>：北京市朝阳区日坛北路6号 <strong>📞 电话</strong>：010-65021717</p>',39)])])}const c=a(n,[["render",i]]);export{f as __pageData,c as default};
